const getListing = async (setter) => {
	const result = await fetch('http://localhost:5001/shop')
	const data = await result.json()
	setter(() => {
		let newListing = []
		data.forEach(data => newListing.push(data))
		return newListing
	})
}

const getFilteredListing = async (setter, endpoint) => {
	const result = await fetch(`http://localhost:5001/filter?${endpoint}`)
	const data = await result.json()
	setter(() => {
		let newListing = []
		data.forEach(listing => newListing.push(listing))
		return newListing
	})
}

const getDesigner = async () => {
	(async () => {
		const result = await fetch('http://localhost:5001/designers')
		const data = await result.json()
		setDesigners(() => {
			let newDesigners = []
			data.forEach(designer => newDesigners.push(designer))
			return newDesigners
		})
	})();
}


export {getListing, getFilteredListing}
